qry:select.qry:xquery:
				for $r in sql('  
SELECT 
	L.oi_personal_emp, 
	TTAPER.d_nro_tarjeta,
	TTAPER.e_nro_legajo_reloj
FROM 
	PER02_PERSONAL_EMP AS L, 
	PER01_PERSONAL AS PER,
	TTA04_PERSONAL AS TTAPER
	{%? (#F:@oi_clase_org !='') {% , ORG02_ESTRUC_PERS%} {% %} %}
JOIN
	L.oi_personal INNER PER.oi_personal,
	TTAPER.oi_personal_emp RIGHT OUTER L.oi_personal_emp
	{%? (#F:@oi_clase_org !='') {% ,L.oi_personal_emp INNER ORG02_ESTRUC_PERS.oi_personal_emp%} {% %} %}
WHERE 
L.oi_empresa = {#F:@oi_empresa}
{%? (#F:@oi_clase_org !='') {% AND ORG02_ESTRUC_PERS.oi_clase_org = {#F:@oi_clase_org} %} {% %} %}
{%? (#F:@oi_indic_activo != '') {% AND L.oi_indic_activo = {#F:@oi_indic_activo} %} {% %} %}
{%? (#F:@oi_tipo_personal != '') {% AND L.oi_tipo_personal = {#F:@oi_tipo_personal} %} {% %} %}
{%? (#F:@oi_ctro_costo_ult != '') {% AND L.oi_ctro_costo_ult = {#F:@oi_ctro_costo_ult} %} {% %} %}
')/ROWS/ROW,
$s in $LEG/PER
join $r/@oi_personal_emp inner $s/@oi_personal_emp
